86	static void submodule_cache_init(struct submodule_cache *cache)
87	{
88		hashmap_init(&cache->for_path, config_path_cmp, NULL, 0);
89		hashmap_init(&cache->for_name, config_name_cmp, NULL, 0);
90		cache->initialized = 1;
91	}
