830	void repo_read_gitmodules(struct repository *repo, int skip_if_read)
831	{
832		submodule_cache_check_init(repo);
833	
834		if (repo->submodule_cache->gitmodules_read && skip_if_read)
835			return;
836	
837		if (repo_read_index(repo) < 0)
838			return;
