860		the_repository->submodule_cache->gitmodules_read = 1;
861	}
862	
863	const struct submodule *submodule_from_name(struct repository *r,
864						    const struct object_id *treeish_name,
865			const char *name)
866	{
867		repo_read_gitmodules(r, 1);
